const upsertProviderModel = `-- name: UpsertProviderModel :one
INSERT INTO provider_models (
    id, provider_id, model_id, display_name, context_limit, features_json,
    pricing_json, parameters_json, is_user_edited, created_at, updated_at
) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
ON CONFLICT(provider_id, model_id) DO UPDATE SET
    display_name = excluded.display_name,
    context_limit = excluded.context_limit,
    features_json = excluded.features_json,
    pricing_json = excluded.pricing_json,
    parameters_json = excluded.parameters_json,
    is_user_edited = excluded.is_user_edited,
    updated_at = excluded.updated_at
RETURNING id, provider_id, model_id, display_name, context_limit, features_json, pricing_json, parameters_json, is_user_edited, created_at, updated_at
`

type UpsertProviderModelParams struct {
	ID             string        `json:"id"`
	ProviderID     string        `json:"provider_id"`
	ModelID        string        `json:"model_id"`
	DisplayName    string        `json:"display_name"`
	ContextLimit   sql.NullInt64 `json:"context_limit"`
	FeaturesJson   string        `json:"features_json"`
	PricingJson    string        `json:"pricing_json"`
	ParametersJson string        `json:"parameters_json"`
	IsUserEdited   int64         `json:"is_user_edited"`
	CreatedAt      string        `json:"created_at"`
	UpdatedAt      string        `json:"updated_at"`
}

// Inserts or updates a provider model (on conflict by provider_id + model_id).
func (q *Queries) UpsertProviderModel(ctx context.Context, arg UpsertProviderModelParams) (*ProviderModel, error) {
	row := q.db.QueryRowContext(ctx, upsertProviderModel,
		arg.ID,
		arg.ProviderID,
		arg.ModelID,
		arg.DisplayName,
		arg.ContextLimit,
		arg.FeaturesJson,
		arg.PricingJson,
		arg.ParametersJson,
		arg.IsUserEdited,
		arg.CreatedAt,
		arg.UpdatedAt,
	)
	var i ProviderModel
	err := row.Scan(
		&i.ID,
		&i.ProviderID,
		&i.ModelID,
		&i.DisplayName,
		&i.ContextLimit,
		&i.FeaturesJson,
		&i.PricingJson,
		&i.ParametersJson,
		&i.IsUserEdited,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return &i, err
}
